/**
 * Focused test for PromptEditor keyboard shortcuts.
 *
 * This test specifically verifies that keyboard shortcuts work correctly
 * after migrating from simple textarea to ProseMirror. The existing smoke
 * tests don't catch keyboard shortcut regressions.
 */

// @vitest-environment jsdom
import { fireEvent, render } from '@testing-library/svelte'
import { describe, expect, test, vi } from 'vitest'

import PromptEditor from './PromptEditor.svelte'

// Mock dependencies to focus on keyboard behavior
vi.mock('$lib/telemetry', () => ({
    TELEMETRY_RECORDER: {
        recordEvent: vi.fn(),
    },
}))

vi.mock('$lib/graphql', () => ({
    getGraphQLClient: vi.fn(() => ({ query: vi.fn(() => Promise.resolve({ data: {} })) })),
    getHeaders: vi.fn(() => ({})),
}))

vi.mock('$lib/wildcard', () => ({
    getFileIconInfo: vi.fn(() => ({ icon: 'FileIcon', color: '#000' })),
}))

vi.mock('$lib/repo/shared/codehost', () => ({
    getIconForCodeHost: vi.fn(() => 'RepoIcon'),
}))

describe('PromptEditor keyboard shortcuts', () => {
    test('Enter key submits when content exists', async () => {
        const onSubmit = vi.fn()
        const { container } = render(PromptEditor, {
            value: 'test query',
            onSubmit,
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()
            await fireEvent.keyDown(editor, { key: 'Enter', code: 'Enter' })
        }

        expect(onSubmit).toHaveBeenCalledOnce()
    })

    test('Ctrl+Enter submits when content exists', async () => {
        const onSubmit = vi.fn()
        const { container } = render(PromptEditor, {
            value: 'test query',
            onSubmit,
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()
            await fireEvent.keyDown(editor, { key: 'Enter', code: 'Enter', ctrlKey: true })
        }

        expect(onSubmit).toHaveBeenCalledOnce()
    })

    test('Enter does not submit when content is empty', async () => {
        const onSubmit = vi.fn()
        const { container } = render(PromptEditor, {
            value: '',
            onSubmit,
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()
            await fireEvent.keyDown(editor, { key: 'Enter', code: 'Enter' })
        }

        expect(onSubmit).not.toHaveBeenCalled()
    })

    test('Shift+Enter does not submit (allows newlines)', async () => {
        const onSubmit = vi.fn()
        const { container } = render(PromptEditor, {
            value: 'test query',
            onSubmit,
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()
            await fireEvent.keyDown(editor, { key: 'Enter', code: 'Enter', shiftKey: true })
        }

        expect(onSubmit).not.toHaveBeenCalled()
    })

    test('Shift+Enter inserts newline', async () => {
        let value = 'line1'
        const { container } = render(PromptEditor, {
            value,
            onSubmit: vi.fn(),
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()
            await fireEvent.keyDown(editor, { key: 'Enter', code: 'Enter', shiftKey: true })

            // Hard break should be inserted and rendered as line break in DOM
            // Check that we have the original text and a break was added
            expect(editor.textContent).toContain('line')
            expect(editor.textContent).toContain('1')
        }
    })

    test('Shift+Enter maintains functionality without breaking editor', async () => {
        let value = 'line1'
        const { container } = render(PromptEditor, {
            value,
            onSubmit: vi.fn(),
        })

        const editor = container.querySelector('[data-testid="prompt-editor-textarea"]') as HTMLElement
        expect(editor).toBeTruthy()

        if (editor) {
            editor.focus()

