import { Plugin, PluginKey, TextSelection } from 'prosemirror-state'
import { Decoration, DecorationSet } from 'prosemirror-view'

/**
 * Detect @ mention at cursor position
 */
function detectMentionAtCursor(text: string, cursorPos: number): { atPos: number; query: string } | null {
    // Find latest @ before cursor
    let atPos = -1
    for (let i = cursorPos - 1; i >= 0; i--) {
        if (text[i] === '@') {
            atPos = i
            break
        }
        // Only break on newlines, allow spaces in mentions
        if (text[i] === '\n') {
            break
        }
    }

    if (atPos >= 0) {
        const afterAt = text.slice(atPos + 1, cursorPos)
        // Allow spaces in mention queries, only reject newlines
        if (!afterAt.includes('\n')) {
            return { atPos, query: afterAt }
        }
    }

    return null
}

