        ArrowDown: (_state, _dispatch, view) => {
            const suggestionState = opts.getSuggestionState?.()
            if (suggestionState && suggestionState.suggestions.length > 0) {
                suggestionState.navigateSelection('down')
                return true // Handled
            }
            return false // Let ProseMirror handle
        },

        ArrowUp: (_state, _dispatch, view) => {
            const suggestionState = opts.getSuggestionState?.()
            if (suggestionState && suggestionState.suggestions.length > 0) {
                suggestionState.navigateSelection('up')
                return true // Handled
            }
            return false // Let ProseMirror handle
        },

        // Handle Cmd/Ctrl+Enter for form submission
        'Mod-Enter': (_state, _dispatch, view) => {
            const value = opts.getValue?.()
            if (!opts.disabled?.() && value?.trim() && opts.onSubmit) {
                opts.onSubmit()
                return true // Handled
            }
            return false // Let ProseMirror handle
        },

        // Handle Enter key for suggestion selection OR form submission
        Enter: (state, dispatch, view) => {
            const suggestionState = opts.getSuggestionState?.()

            // If suggestions are active, select the current suggestion
            if (suggestionState && suggestionState.suggestions.length > 0) {
                const currentSuggestion = suggestionState.suggestions[suggestionState.selectedIndex]
                if (currentSuggestion) {
                    suggestionState.selectSuggestion(currentSuggestion)
                    return true // Handled
                }
            }

            // If no suggestions, handle form submission
            const value = opts.getValue?.()
            if (!opts.disabled?.() && value?.trim() && opts.onSubmit) {
                opts.onSubmit()
                return true // Handled
            }

            return false // Let ProseMirror handle (will create new line)
        },

        // Handle Tab key for suggestion selection
        Tab: (state, dispatch, view) => {
            const suggestionState = opts.getSuggestionState?.()

            // If suggestions are active, select the current suggestion with Tab
            if (suggestionState && suggestionState.suggestions.length > 0) {
                const currentSuggestion = suggestionState.suggestions[suggestionState.selectedIndex]
                if (currentSuggestion) {
                    suggestionState.selectSuggestion(currentSuggestion)
                    return true // Handled
                }
            }

            return false // Let ProseMirror handle default Tab behavior
        },

        // Handle Shift+Enter for explicit newlines
        'Shift-Enter': (state, dispatch, view) => {
            // Use ProseMirror's built-in hard break insertion to properly handle cursor positioning
            const { hard_break } = state.schema.nodes
            if (!hard_break || !dispatch) {
                return false
            }

            const tr = state.tr.replaceSelectionWith(hard_break.create())
            dispatch(tr)
            return true // Prevent submit logic
        },

        // Handle Escape to close suggestions
        Escape: (state, dispatch, view) => {
            // Check if we're in mention mode (regardless of whether suggestions are showing)
            const pmMention = mentionKey.getState(state) as MentionState | null

            if (!pmMention || !pmMention.active) {
                return false // Not in mention mode, let ProseMirror handle
            }

            // Hide suggestions if they're showing
            const suggestionState = opts.getSuggestionState?.()
            if (suggestionState) {
                suggestionState.hideSuggestions()
            }

            // Delete the entire @mention text (from @ symbol to current cursor position)
            // This works whether suggestions are showing or not
            if (dispatch) {
                const tr = state.tr.delete(pmMention.from, pmMention.to)
                dispatch(tr)
            }

            return true // Handled
        },
    })
}

export interface ImagePluginCallbacks {
    onFiles: (files: File[]) => void
}

export function imagePlugin(callbacks: ImagePluginCallbacks): Plugin {
    return new Plugin({
        props: {
            handlePaste: (_view, event) => {
                const clipboard = (event as ClipboardEvent).clipboardData
                if (!clipboard) {
                    return false
                }

                const files: File[] = []
                for (const item of Array.from(clipboard.items)) {
                    const file = item.getAsFile()
                    if (file) {
                        files.push(file)
                    }
                }

                if (files.length > 0) {
                    event.preventDefault()
                    callbacks.onFiles(files)
                    return true
                }

                return false
            },

            handleDrop: (_view, event) => {
                const dataTransfer = (event as DragEvent).dataTransfer
                if (!dataTransfer || dataTransfer.files.length === 0) {
                    return false
                }

                event.preventDefault()
                callbacks.onFiles(Array.from(dataTransfer.files))
                return true
            },

            transformPasted: slice => {
                const stripFormatting = (frag: Fragment): Fragment =>
                    Fragment.fromArray(
                        frag.content
                            .map(node => {
                                if (node.type.name === 'image') {
                                    return null
                                }
                                const stripped = node.childCount ? node.copy(stripFormatting(node.content)) : node
                                return stripped.mark([])
                            })
                            .filter(Boolean) as any[]
                    )

                return new Slice(stripFormatting(slice.content), slice.openStart, slice.openEnd)
            },
        },
    })
}

