        Escape: (state, dispatch, view) => {
            // Check if we're in mention mode (regardless of whether suggestions are showing)
            const pmMention = mentionKey.getState(state) as MentionState | null

            if (!pmMention || !pmMention.active) {
                return false // Not in mention mode, let ProseMirror handle
            }

            // Hide suggestions if they're showing
            const suggestionState = opts.getSuggestionState?.()
            if (suggestionState) {
                suggestionState.hideSuggestions()
            }

            // Delete the entire @mention text (from @ symbol to current cursor position)
            // This works whether suggestions are showing or not
            if (dispatch) {
                const tr = state.tr.delete(pmMention.from, pmMention.to)
                dispatch(tr)
            }

            return true // Handled
        },
    })
}

export interface ImagePluginCallbacks {
