import { schema as basicSchema } from 'prosemirror-schema-basic'
import { EditorState, TextSelection } from 'prosemirror-state'
import { describe, expect, test } from 'vitest'

import { detectMentionAtCursor, editorSchema, mentionKey, mentionPlugin } from './PromptEditor.plugins'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Build a ProseMirror EditorState from a plain string.
 * Newlines in the string become hard_break nodes inside a single paragraph.
 * The cursor is placed at the very end of the content.
 */
function stateFromText(text: string, cursorAtEnd = true): EditorState {
    const schema = editorSchema

    // Build inline content from a single-line string (no newlines expected here).
    const buildInlineContent = (line: string) => {
        if (line.length === 0) return []
        return [schema.text(line)]
    }

    // Split on newlines and interleave hard_break nodes.
    const lines = text.split('\n')
    const inlineNodes: ReturnType<typeof schema.text>[] = []
    for (let i = 0; i < lines.length; i++) {
        inlineNodes.push(...buildInlineContent(lines[i]))
        if (i < lines.length - 1) {
            inlineNodes.push(schema.node('hard_break'))
        }
    }

    const para = schema.node('paragraph', null, inlineNodes.length > 0 ? inlineNodes : [])
    const doc = schema.node('doc', null, [para])

    const state = EditorState.create({
        doc,
        plugins: [mentionPlugin({ onChange: () => {} })],
    })

    if (cursorAtEnd) {
        // Place cursor at the very end (inside the paragraph, after last character).
        const endPos = doc.content.size - 1 // last position inside the paragraph
        const tr = state.tr.setSelection(TextSelection.create(state.doc, endPos))
        return state.apply(tr)
    }

    return state
}

/**
 * Build a multi-paragraph EditorState. Each element of `paragraphs` becomes
 * a separate paragraph node. The cursor is placed at the end of the last paragraph.
 */
function stateFromParagraphs(paragraphs: string[]): EditorState {
    const schema = editorSchema

    const paraNodes = paragraphs.map(text => {
        const content = text.length > 0 ? [schema.text(text)] : []
        return schema.node('paragraph', null, content)
    })

    const doc = schema.node('doc', null, paraNodes)

    const state = EditorState.create({
        doc,
        plugins: [mentionPlugin({ onChange: () => {} })],
    })

    // Place cursor at the end of the last paragraph.
    const lastParaEnd = doc.content.size - 1
    const tr = state.tr.setSelection(TextSelection.create(state.doc, lastParaEnd))
    return state.apply(tr)
}

/**
 * Place the cursor immediately after a character sequence within a state.
 * Returns the new state with the cursor positioned after the first occurrence
 * of `marker` in the document text (absolute PM position).
 */
function stateWithCursorAfter(state: EditorState, marker: string): EditorState {
    const fullText = state.doc.textContent
    const idx = fullText.indexOf(marker)
    if (idx === -1) throw new Error(`Marker "${marker}" not found in document`)

    // We need to find the absolute PM position of the character after the marker.
    // Walk through the doc to map flat text offset to PM position.
    let flatOffset = 0
    let pmPos = -1
    state.doc.nodesBetween(0, state.doc.content.size, (node, pos) => {
        if (node.isText) {
            const text = node.text!
            for (let i = 0; i < text.length; i++) {
                if (flatOffset === idx + marker.length - 1) {
                    pmPos = pos + i + 1 // position AFTER this character
                }
                flatOffset++
            }
        }
    })

    if (pmPos === -1) throw new Error(`Could not locate PM position for marker "${marker}"`)
    const tr = state.tr.setSelection(TextSelection.create(state.doc, pmPos))
    return state.apply(tr)
}

// ---------------------------------------------------------------------------
// detectMentionAtCursor – unit tests
// ---------------------------------------------------------------------------

describe('detectMentionAtCursor', () => {
    test('returns null when no @ present', () => {
        expect(detectMentionAtCursor('hello world', 11)).toBeNull()
    })

    test('detects @ at the start of text', () => {
        const result = detectMentionAtCursor('@repo', 5)
        expect(result).toEqual({ atPos: 0, query: 'repo' })
    })

    test('detects @ in the middle of text', () => {
        const result = detectMentionAtCursor('hello @repo', 11)
        expect(result).toEqual({ atPos: 6, query: 'repo' })
    })

    test('detects @ with empty query (cursor right after @)', () => {
        const result = detectMentionAtCursor('hello @', 7)
        expect(result).toEqual({ atPos: 6, query: '' })
    })

    test('detects @ with spaces in query', () => {
        const result = detectMentionAtCursor('hello @my repo', 14)
        expect(result).toEqual({ atPos: 6, query: 'my repo' })
    })

    test('does not cross newline boundary', () => {
        // Newline before @ means the @ is on a previous "line" and should not be detected
        const result = detectMentionAtCursor('@repo\nhello', 11)
        expect(result).toBeNull()
    })

    test('detects @ on a line after a newline', () => {
        // Simulates hard_break producing '\n' before '@'
        const result = detectMentionAtCursor('first line\n@repo', 16)
        expect(result).toEqual({ atPos: 11, query: 'repo' })
    })

    test('returns null when @ is before a newline and cursor is after the newline', () => {
        const result = detectMentionAtCursor('@repo\nhello', 11)
        expect(result).toBeNull()
    })
})

// ---------------------------------------------------------------------------
// mentionPlugin state – integration tests
// ---------------------------------------------------------------------------

describe('mentionPlugin state', () => {
    // ------------------------------------------------------------------
    // Single-paragraph scenarios
    // ------------------------------------------------------------------

    test('single-line: no mention → state is null', () => {
        const state = stateFromText('hello world')
        const mentionState = mentionKey.getState(state)
        expect(mentionState).toBeNull()
    })

    test('single-line: detects mention with correct from/to positions', () => {
        const state = stateFromText('hello @repo')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.active).toBe(true)
        expect(mentionState!.query).toBe('repo')

        // Verify from points to the '@' character in the document.
        // doc: [para_open(0), 'hello @repo'(1-11), para_close], '@' is at position 7.
        const docText = state.doc.textContent
        expect(docText[mentionState!.from - 1]).toBe('@')
    })

    test('single-line: @ at start of text has from=1 (first char inside para)', () => {
        const state = stateFromText('@myrepo')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('myrepo')
        // '@' is the very first character inside the paragraph (position 1)
        expect(mentionState!.from).toBe(1)
    })

    test('single-line: partial query (cursor mid-word)', () => {
        // Build state with cursor after "@re" (not end of "@repo")
        const baseState = stateFromText('@repo', false)
        const state = stateWithCursorAfter(baseState, '@re')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('re')
    })

    // ------------------------------------------------------------------
    // Multi-paragraph scenarios
    // ------------------------------------------------------------------

    test('multi-paragraph: cursor in second paragraph, @ detected with correct position', () => {
        const state = stateFromParagraphs(['first paragraph', '@repo'])
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.active).toBe(true)
        expect(mentionState!.query).toBe('repo')

        // The '@' must be inside the second paragraph.
        // Verify by resolving the position: the character at from should be '@'.
        const resolvedAt = state.doc.resolve(mentionState!.from)
        expect(resolvedAt.parent.textContent[resolvedAt.parentOffset]).toBe('@')
    })

    test('multi-paragraph: cursor in third paragraph, position is correct', () => {
        const state = stateFromParagraphs(['para one', 'para two', '@hello world'])
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('hello world')

        const resolvedAt = state.doc.resolve(mentionState!.from)
        expect(resolvedAt.parent.textContent[resolvedAt.parentOffset]).toBe('@')
    })

    test('multi-paragraph: no @ in last paragraph → null', () => {
        const state = stateFromParagraphs(['@mention in first', 'plain second'])
        const mentionState = mentionKey.getState(state)
        expect(mentionState).toBeNull()
    })

    test('multi-paragraph: @ in first paragraph does not bleed into second', () => {
        // Cursor is at end of second paragraph (no @)
        const state = stateFromParagraphs(['@first', 'second'])
        const mentionState = mentionKey.getState(state)
        expect(mentionState).toBeNull()
    })

    // ------------------------------------------------------------------
    // Hard-break (Shift+Enter) scenarios
    // ------------------------------------------------------------------

    test('hard-break: @ after hard-break is detected with correct position', () => {
        // Single paragraph containing a hard_break before '@repo'
        const state = stateFromText('before\n@repo')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('repo')

        // Verify the 'from' position resolves to '@' in the document.
        const resolvedAt = state.doc.resolve(mentionState!.from)
        expect(resolvedAt.parent.textContent[resolvedAt.parentOffset]).toBe('@')
    })

    test('hard-break: @ before hard-break is not detected when cursor is after the break', () => {
        // Cursor is at the end of "after" (the line after the hard_break).
        // '@before' is on the first line, so mention detection should stop at the hard_break.
        const baseState = stateFromText('@before\nafter')
        // Move cursor to the end (which is already after "after")
        const mentionState = mentionKey.getState(baseState)
        expect(mentionState).toBeNull()
    })

    // ------------------------------------------------------------------
    // Edge cases
    // ------------------------------------------------------------------

    test('@ at start of second paragraph', () => {
        const state = stateFromParagraphs(['', '@start'])
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
