    // We need to find the absolute PM position of the character after the marker.
    // Walk through the doc to map flat text offset to PM position.
    let flatOffset = 0
    let pmPos = -1
    state.doc.nodesBetween(0, state.doc.content.size, (node, pos) => {
        if (node.isText) {
