 * Newlines in the string become hard_break nodes inside a single paragraph.
 * The cursor is placed at the very end of the content.
 */
function stateFromText(text: string, cursorAtEnd = true): EditorState {
    const schema = editorSchema

    // Build inline content from a single-line string (no newlines expected here).
    const buildInlineContent = (line: string) => {
        if (line.length === 0) return []
        return [schema.text(line)]
    }

    // Split on newlines and interleave hard_break nodes.
    const lines = text.split('\n')
    const inlineNodes: ReturnType<typeof schema.text>[] = []
    for (let i = 0; i < lines.length; i++) {
        inlineNodes.push(...buildInlineContent(lines[i]))
        if (i < lines.length - 1) {
            inlineNodes.push(schema.node('hard_break'))
        }
    }

    const para = schema.node('paragraph', null, inlineNodes.length > 0 ? inlineNodes : [])
    const doc = schema.node('doc', null, [para])

    const state = EditorState.create({
        doc,
        plugins: [mentionPlugin({ onChange: () => {} })],
    })

    if (cursorAtEnd) {
        // Place cursor at the very end (inside the paragraph, after last character).
        const endPos = doc.content.size - 1 // last position inside the paragraph
        const tr = state.tr.setSelection(TextSelection.create(state.doc, endPos))
        return state.apply(tr)
    }

    return state
}

