function stateWithCursorAfter(state: EditorState, marker: string): EditorState {
    const fullText = state.doc.textContent
    const idx = fullText.indexOf(marker)
    if (idx === -1) throw new Error(`Marker "${marker}" not found in document`)

    // We need to find the absolute PM position of the character after the marker.
    // Walk through the doc to map flat text offset to PM position.
    let flatOffset = 0
    let pmPos = -1
    state.doc.nodesBetween(0, state.doc.content.size, (node, pos) => {
        if (node.isText) {
            const text = node.text!
            for (let i = 0; i < text.length; i++) {
                if (flatOffset === idx + marker.length - 1) {
                    pmPos = pos + i + 1 // position AFTER this character
                }
                flatOffset++
            }
        }
    })

    if (pmPos === -1) throw new Error(`Could not locate PM position for marker "${marker}"`)
    const tr = state.tr.setSelection(TextSelection.create(state.doc, pmPos))
    return state.apply(tr)
}

