// ---------------------------------------------------------------------------

describe('detectMentionAtCursor', () => {
    test('returns null when no @ present', () => {
        expect(detectMentionAtCursor('hello world', 11)).toBeNull()
    })

    test('detects @ at the start of text', () => {
        const result = detectMentionAtCursor('@repo', 5)
        expect(result).toEqual({ atPos: 0, query: 'repo' })
    })

    test('detects @ in the middle of text', () => {
        const result = detectMentionAtCursor('hello @repo', 11)
        expect(result).toEqual({ atPos: 6, query: 'repo' })
    })

    test('detects @ with empty query (cursor right after @)', () => {
        const result = detectMentionAtCursor('hello @', 7)
        expect(result).toEqual({ atPos: 6, query: '' })
    })

    test('detects @ with spaces in query', () => {
        const result = detectMentionAtCursor('hello @my repo', 14)
        expect(result).toEqual({ atPos: 6, query: 'my repo' })
    })

    test('does not cross newline boundary', () => {
        // Newline before @ means the @ is on a previous "line" and should not be detected
        const result = detectMentionAtCursor('@repo\nhello', 11)
        expect(result).toBeNull()
    })

    test('detects @ on a line after a newline', () => {
        // Simulates hard_break producing '\n' before '@'
        const result = detectMentionAtCursor('first line\n@repo', 16)
        expect(result).toEqual({ atPos: 11, query: 'repo' })
    })

    test('returns null when @ is before a newline and cursor is after the newline', () => {
        const result = detectMentionAtCursor('@repo\nhello', 11)
        expect(result).toBeNull()
    })
})

