        const baseState = stateFromText('@repo', false)
        const state = stateWithCursorAfter(baseState, '@re')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('re')
    })

