        const charAtFrom = state.doc.textBetween(mentionState!.from, mentionState!.from + 1, undefined, '')
        expect(charAtFrom).toBe('@')
    })

    test('hard-break: @ before hard-break is not detected when cursor is after the break', () => {
        // Cursor is at the end of "after" (the line after the hard_break).
        // '@before' is on the first line, so mention detection should stop at the hard_break.
        const baseState = stateFromText('@before\nafter')
        // Move cursor to the end (which is already after "after")
        const mentionState = mentionKey.getState(baseState)
        expect(mentionState).toBeNull()
    })

    // ------------------------------------------------------------------
    // Edge cases
    // ------------------------------------------------------------------

    test('@ at start of second paragraph', () => {
        const state = stateFromParagraphs(['', '@start'])
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('start')
    })

    test('@ after whitespace', () => {
        const state = stateFromText('   @spaced')
        const mentionState = mentionKey.getState(state)

        expect(mentionState).not.toBeNull()
        expect(mentionState!.query).toBe('spaced')
    })

    test('empty document has no mention', () => {
        const state = stateFromText('')
        const mentionState = mentionKey.getState(state)
        expect(mentionState).toBeNull()
    })
})

