import { keymap } from 'prosemirror-keymap'
import { Fragment, Slice } from 'prosemirror-model'
import { schema as basicSchema } from 'prosemirror-schema-basic'
import { Plugin, PluginKey, TextSelection } from 'prosemirror-state'
import { Decoration, DecorationSet } from 'prosemirror-view'

/**
 * Detect @ mention at cursor position
 */
export function detectMentionAtCursor(text: string, cursorPos: number): { atPos: number; query: string } | null {
    // Find latest @ before cursor
    let atPos = -1
    for (let i = cursorPos - 1; i >= 0; i--) {
        if (text[i] === '@') {
            atPos = i
            break
        }
        // Only break on newlines, allow spaces in mentions
        if (text[i] === '\n') {
            break
        }
    }

    if (atPos >= 0) {
        const afterAt = text.slice(atPos + 1, cursorPos)
        // Allow spaces in mention queries, only reject newlines
        if (!afterAt.includes('\n')) {
            return { atPos, query: afterAt }
        }
    }

    return null
}

// Coords type for ProseMirror coordsAtPos
type Coords = { left: number; right: number; top: number; bottom: number }

// Use basic ProseMirror schema directly
export const editorSchema = basicSchema

// Mention state interface
export type MentionState = {
    active: boolean
    from: number // pos of "@"
    to: number // current cursor
    query: string
} | null

export const mentionKey = new PluginKey<MentionState>('mention')

// Mention detection plugin
export function mentionPlugin(opts: { onChange: (state: MentionState, coords?: Coords) => void }): Plugin {
    return new Plugin<MentionState>({
        key: mentionKey,
        state: {
            init: (): MentionState => null,
            apply(tr, prev, _oldState, newState): MentionState {
                const sel = newState.selection as TextSelection
                if (!sel.empty) return null // Only handle cursor selection

                const $cursor = newState.doc.resolve(sel.from)
                const parentStart = $cursor.start() // PM position of start of parent node's content
                const parentOffset = $cursor.parentOffset // cursor offset within parent node

                // Get text from start of parent block to cursor.
                // Use '\n' as leafText so hard_break nodes act as barriers (same size as in PM).
                const textBeforeCursor = $cursor.parent.textBetween(0, parentOffset, undefined, '\n')
                const result = detectMentionAtCursor(textBeforeCursor, textBeforeCursor.length)

                if (!result) return null

                return {
                    active: true,
                    from: parentStart + result.atPos,
                    to: sel.from,
                    query: result.query,
                }
            },
        },

